<?php $adminTitle='Kids Academy Overview';require_once __DIR__.'/../includes/kids-admin-header.php';$counts=['Published courses'=>(int)$pdo->query("SELECT COUNT(*) FROM kids_courses WHERE status='Published'")->fetchColumn(),'Animated lessons'=>(int)$pdo->query('SELECT COUNT(*) FROM kids_lessons')->fetchColumn(),'Activities'=>(int)$pdo->query('SELECT COUNT(*) FROM kids_activities')->fetchColumn(),'Badges awarded'=>(int)$pdo->query('SELECT COUNT(*) FROM learner_badges')->fetchColumn()];$recent=$pdo->query('SELECT p.*,l.full_name,c.title course_title,kl.title lesson_title FROM learner_progress p JOIN learners l ON l.id=p.learner_id JOIN kids_courses c ON c.id=p.course_id LEFT JOIN kids_lessons kl ON kl.id=p.lesson_id ORDER BY p.updated_at DESC LIMIT 8')->fetchAll();?>
<div class="admin-top"><div><p class="eyebrow">Kids Academy</p><h1>Playful learning, clearly managed.</h1></div><a class="btn btn-premium" href="kids-courses.php?new=1">Create kids course</a></div><div class="row g-4 mb-4"><?php foreach($counts as $label=>$count):?><div class="col-md-6 col-xl-3"><div class="glass-card stat-admin"><span><?=e($label)?></span><strong><?=$count?></strong></div></div><?php endforeach?></div><div class="glass-card"><div class="d-flex justify-content-between align-items-center"><div><p class="eyebrow">Privacy-friendly</p><h2>Recent learner activity</h2></div><span class="tag">No public chat</span></div><div class="table-responsive"><table class="table table-dark align-middle"><thead><tr><th>Learner</th><th>Course</th><th>Lesson</th><th>Status</th><th>Updated</th></tr></thead><tbody><?php foreach($recent as $row):?><tr><td><?=e($row['full_name'])?></td><td><?=e($row['course_title'])?></td><td><?=e($row['lesson_title']??'Activity')?></td><td><?=e($row['status'])?></td><td><?=e(date('M j, Y',strtotime($row['updated_at'])))?></td></tr><?php endforeach?></tbody></table></div></div>
